const a={PENDING:"danger",PROCESSING:"warning",RESOLVED:"success",NEED_HOSPITAL:"danger"},i={SOS:"type-sos",FALL:"type-fall",INACTIVITY:"type-inactivity",LOW_BATTERY:"type-low-battery",DEVICE_OFFLINE:"type-device-offline",ABNORMAL:"type-abnormal"},n={HIGH:"高",MEDIUM:"中",LOW:"低"},r={RESOLVED:"已解决",NEED_HOSPITAL:"需送医",NEED_FOLLOW_UP:"需跟进"};function s(t){if(!t)return"-";const e=new Date(t);return Number.isNaN(e.getTime())?t:new Intl.DateTimeFormat("zh-CN",{month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit"}).format(e)}export{i as a,a as b,r as d,s as f,n as p};
